// Extract safe workflow and execution metadata from the Error Trigger payload.
// Never retain raw exception messages, stack traces, or capture text.
const payload = $input.first().json;

const rawWorkflowName = payload?.workflow?.name ?? null;
const workflowId = payload?.workflow?.id ?? null;

const WORKFLOW_NAME_MAP = {
  'Second Brain - Intake': 'second_brain_intake',
  'Second Brain - Intake': 'second_brain_intake',
  'Second Brain - Error Handler': 'second_brain_error_handler',
  'Second Brain - Error Harness': 'second_brain_error_harness',
};
const workflowName = (rawWorkflowName && WORKFLOW_NAME_MAP[rawWorkflowName])
  ? WORKFLOW_NAME_MAP[rawWorkflowName]
  : 'unknown_workflow';

const executionId = payload?.execution?.id ?? null;
const lastNode = payload?.execution?.lastNodeExecuted ?? null;

const NODE_STAGE_MAP = {
  'Classify with Gemini': 'gemini',
  'Call Gemini Structured Output': 'gemini',
  'Validate Classification': 'classification_validation',
  'Validate Classification Contract': 'classification_validation',
  'Write to Vault': 'Write to Inbox': 'Inbox (classified)': 'Submit to Writer Service': 'writer_service',
  'Submit to Writer Service (inbox)': 'writer_service',
  'Claim Attempt': 'capture_fetch',
  'Get Capture': 'capture_fetch',
  'Acknowledge Filed': 'acknowledge_filed',
  'Acknowledge Inbox': 'acknowledge_inbox',
};
const stage = (lastNode && NODE_STAGE_MAP[lastNode])
  ? NODE_STAGE_MAP[lastNode]
  : 'workflow_unknown';

// Attempt to extract correlation object from the error.
// Stop And Error node serializes the Error Object as the error message.
let rawErrorObject = null;

const execErrMsg = payload?.execution?.error?.message;
if (execErrMsg) {
  if (typeof execErrMsg === 'string') {
    try { rawErrorObject = JSON.parse(execErrMsg); } catch (_) {}
  } else if (typeof execErrMsg === 'object' && execErrMsg !== null) {
    rawErrorObject = execErrMsg;
  }
}

if (!rawErrorObject) {
  const trigErrMsg = payload?.trigger?.error?.message;
  if (trigErrMsg) {
    if (typeof trigErrMsg === 'string') {
      try { rawErrorObject = JSON.parse(trigErrMsg); } catch (_) {}
    } else if (typeof trigErrMsg === 'object' && trigErrMsg !== null) {
      rawErrorObject = trigErrMsg;
    }
  }
}

return [{
  json: {
    workflow_id: workflowId ? String(workflowId) : 'unknown',
    workflow_name: workflowName,
    execution_id: executionId ? String(executionId) : null,
    stage,
    raw_error_object: rawErrorObject,
  }
}];

// Validate correlation fields from the Stop And Error error object.
// Only accept known, allowlisted values — never forward arbitrary error messages.
const data = $input.first().json;

const RETRYABLE = new Set([
  'gemini_timeout', 'gemini_rate_limit', 'gemini_server_error',
  'writer_git_push_rejected', 'writer_git_index_locked', 'writer_service_timeout', 'writer_service_unavailable',
  'capture_service_unavailable', 'classification_validation_failure',
  'unexpected_response_shape', 'workflow_unhandled_exception',
]);
const TERMINAL = new Set([
  'defense_in_depth_secret_detected', 'invalid_webhook_envelope', 'contract_violation',
  'writer_git_conflict', 'writer_git_worktree_dirty', 'writer_path_traversal', 'writer_capture_duplicate',
]);
const ALLOWED_STAGES = new Set([
  'gemini', 'classification_validation', 'writer_service',
  'acknowledge_filed', 'acknowledge_inbox', 'capture_fetch', 'workflow_unknown',
]);
const SAFE_SLUG_RE = /^[A-Za-z0-9_.:-]{1,100}$/;
const CAPTURE_ID_RE = /^SB-\d{8}-\d{4}$/;

const errObj = data.raw_error_object;
let correlated = false;
let capture_id = null;
let delivery_attempt = null;
let disposition = null;
let error_type = null;
let reason_type = null;
let stage = data.stage;

if (errObj && typeof errObj === 'object') {
  const c = errObj.capture_id;
  const da = errObj.delivery_attempt;
  const d = errObj.disposition;
  const et = errObj.error_type;
  const rt = errObj.reason_type ?? 'workflow_error';
  const s = errObj.stage ?? 'workflow_unknown';

  const validCaptureId = typeof c === 'string' && CAPTURE_ID_RE.test(c);
  const validAttempt = Number.isInteger(da) && da >= 1;
  const validDisposition = d === 'retryable' || d === 'terminal';
  const validErrorType = typeof et === 'string' &&
    ((d === 'retryable' && RETRYABLE.has(et)) || (d === 'terminal' && TERMINAL.has(et)));
  const validReasonType = typeof rt === 'string' && SAFE_SLUG_RE.test(rt);
  const validStage = typeof s === 'string' && ALLOWED_STAGES.has(s);

  if (validCaptureId && validAttempt && validDisposition && validErrorType && validReasonType && validStage) {
    correlated = true;
    capture_id = c;
    delivery_attempt = da;
    disposition = d;
    error_type = et;
    reason_type = rt;
    stage = s;
  }
}

return [{
  json: {
    workflow_id: data.workflow_id,
    workflow_name: data.workflow_name,
    execution_id: data.execution_id,
    stage,
    capture_id,
    delivery_attempt,
    disposition,
    error_type,
    reason_type,
    correlated,
  }
}];

// Orphan workflow error: no valid capture correlation context.
// Log safe metadata only — do not guess a capture ID, do not mutate capture-service.
// The stale-lease reaper will recover durable captures after ~330 seconds.
const data = $input.first().json;
console.log(JSON.stringify({
  event: 'orphan_workflow_error',
  workflow_id: data.workflow_id,
  workflow_name: data.workflow_name,
  execution_id: data.execution_id,
  stage: data.stage,
  correlated: false,
  timestamp: new Date().toISOString(),
}));
return [{ json: { recorded: true, correlated: false } }];

// HTTP report to capture-service failed. Log safe metadata only.
// The stale-lease reaper remains the safety net for durable capture recovery.
const data = $input.first().json;
console.log(JSON.stringify({
  event: 'workflow_error_report_failed',
  error_description: data?.error?.description ?? 'unknown',
  error_status: data?.error?.httpCode ?? null,
  timestamp: new Date().toISOString(),
}));
return [{ json: { recorded: true, report_failed: true } }];
